      "Verdict": "Weakly supported."
    },
    "Focal Segmental Glomerulosclerosis": {
      "Supports": "Obesity-related hyperfiltration/glomerulomegaly can lead to secondary FSGS; severe proteinuria.",
      "Arguments against": "Usually associated with lower levels of proteinuria than seen in pure Minimal Change Disease, though possible.",
      "Verdict": "Well-supported (especially given obesity)."
    },
    "Primary membranous nephropathy": {
      "Supports": "Common cause of adult-onset nephrotic syndrome.",
      "Arguments against": "No specific evidence provided; usually more insidious onset.",
      "Verdict": "Weakly supported."
    }
